import{_ as a,o as s,c as n,a2 as t}from"./chunks/framework.DGp-bpT-.js";const g=JSON.parse('{"title":"Concepts","description":"","frontmatter":{},"headers":[],"relativePath":"guide/concepts.md","filePath":"guide/concepts.md"}'),i={name:"guide/concepts.md"};function o(r,e,l,p,c,d){return s(),n("div",null,[...e[0]||(e[0]=[t(`<h1 id="concepts" tabindex="-1">Concepts <a class="header-anchor" href="#concepts" aria-label="Permalink to &quot;Concepts&quot;">​</a></h1><p>Understanding DSO&#39;s internal architecture helps you configure it effectively and debug issues with confidence.</p><h2 id="the-three-components" tabindex="-1">The Three Components <a class="header-anchor" href="#the-three-components" aria-label="Permalink to &quot;The Three Components&quot;">​</a></h2><p>DSO consists of three binaries that work together:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>docker-dso    ← The CLI plugin (docker dso up, down, fetch, watch)</span></span>
<span class="line"><span>dso-agent     ← The background daemon (Unix socket server, secret cache, watcher)</span></span>
<span class="line"><span>dso-provider-* ← One binary per cloud provider (aws, azure, vault, huawei)</span></span></code></pre></div><h3 id="how-they-connect" tabindex="-1">How They Connect <a class="header-anchor" href="#how-they-connect" aria-label="Permalink to &quot;How They Connect&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────────┐</span></span>
<span class="line"><span>│  Your Terminal                               │</span></span>
<span class="line"><span>│                                             │</span></span>
<span class="line"><span>│  $ docker dso up -d                         │</span></span>
<span class="line"><span>│         │                                   │</span></span>
<span class="line"><span>│         ▼                                   │</span></span>
<span class="line"><span>│  docker-dso (CLI plugin)                    │</span></span>
<span class="line"><span>│    ├── reads docker-compose.yml + dso.yaml  │</span></span>
<span class="line"><span>│    ├── connects to dso-agent via Unix socket │</span></span>
<span class="line"><span>│    └── passes enriched env to Docker Engine │</span></span>
<span class="line"><span>│                                             │</span></span>
<span class="line"><span>│  dso-agent (daemon)                         │</span></span>
<span class="line"><span>│    ├── loads dso-provider-aws (RPC binary)  │</span></span>
<span class="line"><span>│    ├── calls GetSecret(&quot;myapp/db&quot;)          │</span></span>
<span class="line"><span>│    ├── stores result in in-memory cache     │</span></span>
<span class="line"><span>│    ├── serves secrets over Unix socket      │</span></span>
<span class="line"><span>│    └── runs Watcher loop (rotation)         │</span></span>
<span class="line"><span>│                                             │</span></span>
<span class="line"><span>│  dso-provider-aws (RPC subprocess)          │</span></span>
<span class="line"><span>│    ├── calls AWS Secrets Manager API        │</span></span>
<span class="line"><span>│    └── returns map[string]string values     │</span></span>
<span class="line"><span>└─────────────────────────────────────────────┘</span></span></code></pre></div><h2 id="the-provider-plugin-system" tabindex="-1">The Provider Plugin System <a class="header-anchor" href="#the-provider-plugin-system" aria-label="Permalink to &quot;The Provider Plugin System&quot;">​</a></h2><p>Providers are separate Go binaries (<code>dso-provider-aws</code>, <code>dso-provider-azure</code>, etc.) that communicate with the agent over <strong>net/rpc</strong> using HashiCorp&#39;s <code>go-plugin</code> framework.</p><p>This design means:</p><ul><li><strong>Each provider is isolated</strong> — a crash in one provider doesn&#39;t affect others</li><li><strong>New providers can be added</strong> without modifying DSO core</li><li><strong>Auth logic is contained</strong> inside the provider binary</li></ul><p>The provider interface has two methods:</p><div class="language-go vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">go</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Init</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(config </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">map</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">string</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">string</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">error</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">GetSecret</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(name </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">string</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) (</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">map</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">string</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">string</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">error</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><h2 id="secret-injection-flow" tabindex="-1">Secret Injection Flow <a class="header-anchor" href="#secret-injection-flow" aria-label="Permalink to &quot;Secret Injection Flow&quot;">​</a></h2><p>When you run <code>docker dso up -d</code>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. CLI reads dso.yaml → knows: provider=aws, secrets=[myapp/db], inject=env</span></span>
<span class="line"><span>2. CLI connects to agent via Unix socket</span></span>
<span class="line"><span>3. Agent calls dso-provider-aws → GetSecret(&quot;myapp/db&quot;)</span></span>
<span class="line"><span>4. AWS returns: {&quot;DB_PASSWORD&quot;: &quot;s3cr3t&quot;, &quot;DB_USER&quot;: &quot;myapp&quot;}</span></span>
<span class="line"><span>5. Agent applies mappings from dso.yaml:</span></span>
<span class="line"><span>     DB_PASSWORD → DB_PASSWORD  (in container env)</span></span>
<span class="line"><span>     DB_USER → DB_USER</span></span>
<span class="line"><span>6. CLI writes enriched env to a temp file</span></span>
<span class="line"><span>7. CLI calls: docker compose --env-file /tmp/dso-*.env up -d</span></span>
<span class="line"><span>8. Docker Engine starts containers with secrets in their environment</span></span></code></pre></div><div class="important custom-block github-alert"><p class="custom-block-title">IMPORTANT</p><p>Secrets are injected via Docker&#39;s standard environment variable mechanism — the agent does <strong>not</strong> modify the Docker image or write to any persistent storage.</p></div><h2 id="how-secret-rotation-works" tabindex="-1">How Secret Rotation Works <a class="header-anchor" href="#how-secret-rotation-works" aria-label="Permalink to &quot;How Secret Rotation Works&quot;">​</a></h2><h3 id="polling-mechanism" tabindex="-1">Polling Mechanism <a class="header-anchor" href="#polling-mechanism" aria-label="Permalink to &quot;Polling Mechanism&quot;">​</a></h3><p>When <code>rotation: true</code> is set on a secret, the agent starts a background polling loop:</p><ul><li><strong>Default polling interval:</strong> 2 minutes (configurable per-environment)</li><li>DSO polls the upstream cloud providers at these defined intervals.</li><li>Example Configuration: <code>agent.watch.polling_interval: 30s</code></li></ul><h3 id="atomic-update-process" tabindex="-1">Atomic Update Process <a class="header-anchor" href="#atomic-update-process" aria-label="Permalink to &quot;Atomic Update Process&quot;">​</a></h3><ol><li>DSO detects a secret change in the upstream provider by hashing the new payload.</li><li>It fetches the new value while continuing to hold the old value in memory, ensuring zero downtime.</li><li>It applies the update based on the configured injection strategy: <ul><li><strong>env</strong>: Sends a <code>SIGHUP</code> (or custom <code>reload_signal</code>) to the running container, prompting the application to reload its environment cleanly.</li><li><strong>file</strong>: Uses an atomic rename operation on the mounted tmpfs payload. It writes the new secret to a temporary file, calls <code>rename()</code> to swap it, and unlinks the old file. This guarantees that file-watching applications never read a partially written secret.</li><li><strong>restart</strong>: Performs a graceful container restart with health check verification.</li></ul></li></ol><h3 id="handling-rotation-failures" tabindex="-1">Handling Rotation Failures <a class="header-anchor" href="#handling-rotation-failures" aria-label="Permalink to &quot;Handling Rotation Failures&quot;">​</a></h3><ul><li><strong>Resilience:</strong> If the new secret is invalid, malformed, or the provider API is unreachable, DSO aborts the rotation and retains the old valid value.</li><li><strong>Audit Logging:</strong> The error is immediately recorded to the structured JSON audit log.</li><li><strong>Retry Backoff:</strong> DSO supports configurable retry attempts and exponential backoff, preventing rate-limiting from cloud providers during outages.</li></ul><h3 id="debouncer" tabindex="-1">Debouncer <a class="header-anchor" href="#debouncer" aria-label="Permalink to &quot;Debouncer&quot;">​</a></h3><p>The watcher includes a debouncer that prevents multiple rapid vault changes from triggering multiple rotations. If 3 secret updates arrive within 30 seconds, only one rotation event fires.</p><h2 id="the-strategy-engine" tabindex="-1">The Strategy Engine <a class="header-anchor" href="#the-strategy-engine" aria-label="Permalink to &quot;The Strategy Engine&quot;">​</a></h2><p>Before rotating a container, DSO analyzes it and computes a <strong>score (0–100)</strong>:</p><table tabindex="0"><thead><tr><th>Check</th><th>Deduction</th><th>Reason</th></tr></thead><tbody><tr><td>Fixed host port (e.g., <code>80:80</code>)</td><td>-50</td><td>Can&#39;t run two containers on same port</td></tr><tr><td>Explicit <code>container_name</code></td><td>-20</td><td>Name conflict with parallel container</td></tr><tr><td><code>restart: always</code> policy</td><td>-20</td><td>Conflicts with rotation engine</td></tr><tr><td>No <code>healthcheck</code> defined</td><td>-10</td><td>Can&#39;t validate safe cutover</td></tr><tr><td>Stateful workload (MySQL, Postgres, <code>/var/lib/</code> mounts)</td><td>-20</td><td>Data corruption risk</td></tr></tbody></table><p><strong>Scoring result:</strong></p><ul><li>Score ≥ 70 → <strong>Rolling (Blue/Green)</strong> update</li><li>Score &lt; 70 → <strong>Graceful restart</strong></li></ul><h3 id="rolling-update-flow" tabindex="-1">Rolling Update Flow <a class="header-anchor" href="#rolling-update-flow" aria-label="Permalink to &quot;Rolling Update Flow&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. Clone the container with updated environment</span></span>
<span class="line"><span>2. Start the new container</span></span>
<span class="line"><span>3. Wait for healthcheck to pass (health_check_timeout)</span></span>
<span class="line"><span>4. Remove the old container</span></span></code></pre></div><h3 id="graceful-restart-flow" tabindex="-1">Graceful Restart Flow <a class="header-anchor" href="#graceful-restart-flow" aria-label="Permalink to &quot;Graceful Restart Flow&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. Stop the container (with grace_period)</span></span>
<span class="line"><span>2. Restart it with the updated environment</span></span></code></pre></div><h2 id="reload-strategies" tabindex="-1">Reload Strategies <a class="header-anchor" href="#reload-strategies" aria-label="Permalink to &quot;Reload Strategies&quot;">​</a></h2><p>The <code>reload_strategy</code> field controls what happens <em>inside</em> the container after rotation:</p><table tabindex="0"><thead><tr><th>Strategy</th><th>Behavior</th></tr></thead><tbody><tr><td><code>signal</code></td><td>Sends <code>SIGHUP</code> to the container&#39;s main process — ideal for apps that reload config on signal (Nginx, many Go/Python apps)</td></tr><tr><td><code>restart</code></td><td>Restarts the container (safe for stateless services)</td></tr><tr><td><code>none</code></td><td>Updates the cached value but does not signal the container</td></tr></tbody></table><h2 id="in-memory-cache" tabindex="-1">In-Memory Cache <a class="header-anchor" href="#in-memory-cache" aria-label="Permalink to &quot;In-Memory Cache&quot;">​</a></h2><p>The agent maintains a thread-safe in-memory cache of all fetched secrets. This serves two purposes:</p><ol><li><strong>Performance</strong> — avoids hitting the cloud API on every container start</li><li><strong>Resilience</strong> — if the cloud provider is temporarily unavailable, the agent serves from cache</li></ol><p>Cache TTL is controlled by <code>agent.refresh_interval</code> in <code>dso.yaml</code>.</p>`,43)])])}const u=a(i,[["render",o]]);export{g as __pageData,u as default};
